import{_ as a,o as r,c as t,ai as o,aj as n}from"./chunks/framework.DG6aArJf.js";const m=JSON.parse('{"title":"A Note from the Creator","description":"","frontmatter":{},"headers":[],"relativePath":"sponsor/note.md","filePath":"sponsor/note.md"}'),i={name:"sponsor/note.md"};function s(p,e,l,c,h,g){return r(),t("div",null,[...e[0]||(e[0]=[o('<p><a href="https://github.com/sponsors/giovanni1707" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/Sponsor-%F0%9F%92%96-pink" alt="Sponsor"></a></p><p><a href="https://paypal.me/GiovanniSylvain" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/Sponsor-PayPal-blue?logo=paypal" alt="Sponsor"></a></p><h1 id="a-note-from-the-creator" tabindex="-1">A Note from the Creator <a class="header-anchor" href="#a-note-from-the-creator" aria-label="Permalink to “A Note from the Creator”">​</a></h1><div class="creator"><img src="'+n+'" alt="Giovanni Marianne" class="creator-photo"><div class="creator-info"><p><strong>Giovanni Marianne</strong></p><p>Creator of DOM Helpers Library</p></div></div><p>DOM Helpers was born out of a deep love for <strong>vanilla JavaScript</strong>.</p><p>Like many developers, I explored frameworks such as React and Vue. I enjoyed working with them, especially their reactivity systems. But over time, I realized something important: I wasn’t abandoning JavaScript because it was weak — I was leaving because <strong>managing complex projects in plain JavaScript becomes hard</strong>.</p><p>I didn’t agree with the idea that the solution was to abandon JavaScript altogether.</p><p>Instead, I chose a different path.</p><h2 id="enhancing-javascript-not-replacing-it" tabindex="-1">Enhancing JavaScript, Not Replacing It <a class="header-anchor" href="#enhancing-javascript-not-replacing-it" aria-label="Permalink to “Enhancing JavaScript, Not Replacing It”">​</a></h2><p>DOM Helpers was created to <strong>enhance JavaScript, not replace it</strong>.<br> It is built on native browser APIs, with no heavy abstractions that hide what’s really happening.</p><p>Every helper exists to make JavaScript <strong>more manageable, more expressive, and more delightful to work with</strong>, while keeping you close to the language itself.</p><h2 id="more-than-a-library" tabindex="-1">More Than a Library <a class="header-anchor" href="#more-than-a-library" aria-label="Permalink to “More Than a Library”">​</a></h2><p>This project is not just a library.</p><p>It is also a <strong>learning platform</strong>.</p><p>When you use DOM Helpers, you are not learning a new language or a complex framework — you are <strong>strengthening your understanding of JavaScript</strong>. You can see how things work under the hood:</p><ul><li>how the DOM updates</li><li>how reactivity is implemented</li><li>how data flows</li></ul><p>The goal is not only productivity, but <strong>growth as a JavaScript developer</strong>.</p><h2 id="open-source-community-driven" tabindex="-1">Open Source &amp; Community-Driven <a class="header-anchor" href="#open-source-community-driven" aria-label="Permalink to “Open Source &amp; Community-Driven”">​</a></h2><p>DOM Helpers is <strong>free and open source</strong>, and it always will be.</p><p>I maintain it with care and passion, and I do my best to keep it simple, transparent, and educational. However, like all open-source projects, it grows and survives through the <strong>community</strong>.</p><p>If DOM Helpers helps you:</p><ul><li>learn JavaScript more deeply</li><li>enjoy coding again without heavy frameworks</li><li>build better projects with confidence</li></ul><p>you can support the project in many ways:</p><ul><li>contributing code, ideas, or documentation</li><li>reporting issues or suggesting improvements</li><li>sponsoring the project to help with long-term maintenance</li></ul><p>Every contribution — big or small — helps keep DOM Helpers <strong>alive, open, and evolving</strong>.</p><p>Thank you for believing in JavaScript.<br> Thank you for being part of this journey.</p>',26)])])}const u=a(i,[["render",s]]);export{m as __pageData,u as default};
